CREATE OR REPLACE FUNCTION public.calculate_trending_score(article_id uuid, base_score numeric DEFAULT 50.0)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
    final_score DECIMAL := base_score;
    article_age_hours INTEGER;
    category_boost DECIMAL := 0.0;
    breaking_boost DECIMAL := 0.0;
    hot_boost DECIMAL := 0.0;
    recency_factor DECIMAL := 1.0;
BEGIN
    -- Get article age in hours
    SELECT EXTRACT(EPOCH FROM (NOW() - created_at)) / 3600
    INTO article_age_hours
    FROM digest_articles
    WHERE id = article_id;

    -- Apply recency factor (newer articles get higher scores)
    IF article_age_hours <= 2 THEN
        recency_factor := 2.0;
    ELSIF article_age_hours <= 6 THEN
        recency_factor := 1.5;
    ELSIF article_age_hours <= 12 THEN
        recency_factor := 1.2;
    ELSIF article_age_hours <= 24 THEN
        recency_factor := 1.0;
    ELSE
        recency_factor := 0.8;
    END IF;

    -- Apply category-specific boosts
    SELECT CASE
        WHEN category IN ('Technology', 'Business') THEN 10.0
        WHEN category IN ('Environment', 'Science') THEN 8.0
        WHEN category IN ('Health', 'Politics') THEN 6.0
        ELSE 5.0
    END INTO category_boost
    FROM digest_articles
    WHERE id = article_id;

    -- Apply breaking/hot article boosts
    SELECT
        CASE WHEN is_breaking THEN 20.0 ELSE 0.0 END,
        CASE WHEN is_hot THEN 15.0 ELSE 0.0 END
    INTO breaking_boost, hot_boost
    FROM digest_articles
    WHERE id = article_id;

    -- Calculate final score
    final_score := (base_score + category_boost + breaking_boost + hot_boost) * recency_factor;

    -- Cap the score at 100
    IF final_score > 100.0 THEN
        final_score := 100.0;
    END IF;

    RETURN final_score;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_old_deleted_notifications(p_days_old integer DEFAULT 30)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    deleted_count INTEGER;
BEGIN
    DELETE FROM notifications
    WHERE is_deleted = TRUE
      AND deleted_at < (CURRENT_TIMESTAMP - INTERVAL '1 day' * p_days_old);

    GET DIAGNOSTICS deleted_count = ROW_COUNT;

    RETURN deleted_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_achievement_notification(p_user_id uuid, p_achievement_id uuid, p_achievement_key character varying, p_achievement_title character varying, p_achievement_description text, p_points_awarded integer)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    notification_id UUID;
BEGIN
    INSERT INTO notifications (
        user_id,
        type,
        title,
        message,
        related_entity_id,
        related_entity_type,
        data,
        created_at
    )
    VALUES (
        p_user_id,
        'achievement_unlocked',
        'Achievement Unlocked!',
        'You unlocked: ' || p_achievement_title,
        p_achievement_id,
        'achievement',
        jsonb_build_object(
            'achievement_id', p_achievement_id,
            'achievement_key', p_achievement_key,
            'achievement_title', p_achievement_title,
            'achievement_description', p_achievement_description,
            'points_awarded', p_points_awarded
        ),
        CURRENT_TIMESTAMP
    )
    RETURNING id INTO notification_id;

    RETURN notification_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.expire_challenges()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Auto-expire challenges that are past their expiry date
    UPDATE challenges
    SET status = 'expired', updated_at = CURRENT_TIMESTAMP
    WHERE expires_at < CURRENT_TIMESTAMP
    AND status IN ('pending', 'accepted');

    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_user_by_supabase_id(p_supabase_id uuid)
 RETURNS TABLE(id uuid, email character varying, name character varying, auth_method character varying, created_at timestamp without time zone, updated_at timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        u.id,
        u.email,
        u.name,
        u.auth_method,
        u.created_at,
        u.updated_at
    FROM users u
    WHERE u.supabase_id = p_supabase_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.migrate_user_to_jwt(p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    affected_rows INTEGER;
BEGIN
    UPDATE users
    SET
        auth_method = 'jwt',
        supabase_id = NULL,
        last_auth_method = 'jwt',
        migrated_at = CURRENT_TIMESTAMP
    WHERE id = p_user_id;

    GET DIAGNOSTICS affected_rows = ROW_COUNT;

    IF affected_rows > 0 THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.migrate_user_to_supabase(p_user_id uuid, p_supabase_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    affected_rows INTEGER;
BEGIN
    -- Check if supabase_id is already in use
    IF EXISTS (SELECT 1 FROM users WHERE supabase_id = p_supabase_id) THEN
        RAISE EXCEPTION 'Supabase ID already linked to another user';
    END IF;

    UPDATE users
    SET
        auth_method = 'supabase',
        supabase_id = p_supabase_id,
        last_auth_method = 'supabase',
        migrated_at = CURRENT_TIMESTAMP
    WHERE id = p_user_id;

    GET DIAGNOSTICS affected_rows = ROW_COUNT;

    IF affected_rows > 0 THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.restore_notification(p_notification_id uuid, p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    affected_rows INTEGER;
BEGIN
    UPDATE notifications
    SET is_deleted = FALSE, deleted_at = NULL
    WHERE id = p_notification_id
      AND user_id = p_user_id
      AND is_deleted = TRUE;

    GET DIAGNOSTICS affected_rows = ROW_COUNT;

    IF affected_rows > 0 THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.soft_delete_notification(p_notification_id uuid, p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    affected_rows INTEGER;
BEGIN
    UPDATE notifications
    SET is_deleted = TRUE, deleted_at = CURRENT_TIMESTAMP
    WHERE id = p_notification_id
      AND user_id = p_user_id
      AND is_deleted = FALSE;

    GET DIAGNOSTICS affected_rows = ROW_COUNT;

    IF affected_rows > 0 THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
END;
$function$
;

