    last_active TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    avatar_url VARCHAR(500),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    auth_method VARCHAR(20) NOT NULL DEFAULT 'jwt'::character varying,
    supabase_id UUID,
    last_auth_method VARCHAR(20) NOT NULL DEFAULT 'jwt'::character varying,
    migrated_at TIMESTAMP,
    CHECK (((auth_method)::text = ANY ((ARRAY['jwt'::character varying, 'supabase'::character varying])::text[]))),
    UNIQUE (email),
    CHECK (((last_auth_method)::text = ANY ((ARRAY['jwt'::character varying, 'supabase'::character varying])::text[]))),
    PRIMARY KEY (id)
);
