-- Views
CREATE OR REPLACE VIEW public.auth_method_stats AS  SELECT auth_method,
    count(*) AS user_count,
    count(
        CASE
            WHEN (migrated_at IS NOT NULL) THEN 1
            ELSE NULL::integer
        END) AS migrated_count,
    min(created_at) AS first_user_created,
    max(last_active) AS last_activity
   FROM users
  GROUP BY auth_method;
